import {
  ChangeDetectionStrategy,
  Component,
  forwardRef,
  InjectionToken,
  model,
  ViewEncapsulation,
} from '@angular/core';

/**
 * Sources — root container for citation cards. Mirrors React `Sources`.
 *
 * Owns the open/close state shared with `SourcesTrigger` and
 * `SourcesContent`. Uncontrolled by default (`open=false`).
 */
export interface SourcesState {
  isOpen: () => boolean;
  setOpen(open: boolean): void;
  toggle(): void;
}

export const SOURCES = new InjectionToken<SourcesState>('SourcesState');

@Component({
  selector: 'sources',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'not-prose mb-4 text-primary text-xs block',
  },
  providers: [{ provide: SOURCES, useExisting: forwardRef(() => Sources) }],
})
export class Sources implements SourcesState {
  readonly open = model<boolean>(false);

  readonly isOpen = () => this.open();

  setOpen(open: boolean): void {
    this.open.set(open);
  }

  toggle(): void {
    this.open.update((v) => !v);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  ViewEncapsulation,
} from '@angular/core';

import { SOURCES } from './sources';

/**
 * SourcesContent — collapsible body. Mirrors React `SourcesContent`.
 */
@Component({
  selector: 'sources-content',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (open()) {
      <div
        class="mt-3 flex w-fit flex-col gap-2 outline-none animate-in slide-in-from-top-2"
      >
        <ng-content />
      </div>
    }
  `,
})
export class SourcesContent {
  private readonly state = inject(SOURCES);
  protected readonly open = computed(() => this.state.isOpen());
}

export { Sources, SOURCES } from './sources';
export type { SourcesState } from './sources';
export { SourcesTrigger } from './sources-trigger';
export { SourcesContent } from './sources-content';
export { Source } from './source';
